INSERT INTO questions (subject, exam_type, question, option_a, option_b, option_c, option_d, option_e, correct_answer, explanation, year) VALUES 
('english', 'WAEC', 'A guest should not make _________ remarks about what he is offered by his host but _________ statements.', 'candid', 'appealing', 'polite', 'complimentary', NULL, 'D', 'Derogatory means insulting or disrespectful. The opposite that best fills the gap is complimentary, meaning praising or expressing approval.', 2020), 
('english', 'WAEC', 'The audience applauded the last speaker, but the first was _________.', 'booed', 'rejected', 'abused', 'scorned', NULL, 'A', 'Applauded refers to clapping in appreciation and praise. The opposite is booed, which means shouting derisively to show disapproval.', 2020), 
('english', 'WAEC', 'The commander said that raw recruits could not dislodge the enemies; he needed _________ men.', 'skilled', 'practical', 'learned', 'seasoned', NULL, 'D', 'Raw means new and inexperienced. The appropriate antonym is seasoned, meaning experienced and skilled with regard to a particular profession.', 2020), 
('english', 'WAEC', 'John gave a fictitious account of the incident but his son''s account was _________.', 'probable', 'compelling', 'necessary', 'factual', NULL, 'D', 'Fictitious means a story that is cooked up, invented or just fabricated. The opposite is factual, true, real.', 2020), 
('english', 'WAEC', 'While the refuse dump smelled fetid, the orchard exuded a _________ smell.', 'fragrant', 'spicy', 'clean', 'dry', NULL, 'A', 'Fetid describes a foul and stinking smell. The opposite is fragrant — something that is sweet-smelling or that has a pleasant scent or fragrance.', 2020), 
('english', 'WAEC', 'Only some of the accused were acquitted; the rest were _________.', 'remanded', 'convicted', 'detained', 'interdicted', NULL, 'B', 'The verb acquit means to exonerate someone or free them from the crime. The opposite is convicted, meaning found guilty of a crime.', 2020), 
('english', 'WAEC', 'The principal chastised Ben for his use of coarse language and advised him to emulate his sister''s _________ behaviour.', 'pure', 'neat', 'refined', 'organised', NULL, 'C', 'Coarse language is rough, rude, uncouth, unpolished, vulgar and raw. The opposite is refined language, used politely and intelligently.', 2020), 
('english', 'WAEC', 'It would have been my pleasure to accept your invitation but I have to _________ because of a previous engagement.', 'jettison', 'defer', 'suspend', 'decline', NULL, 'D', 'To accept an invitation means to honour and attend the programme. The opposite is to decline the invitation, turn it down or reject it.', 2020), 
('english', 'WAEC', 'Older people are expected to be _________ where youths are green.', 'experienced', 'cautious', 'equipped', 'considerate', NULL, 'A', 'The adjective green describes someone who is inexperienced, unexposed and who lacks adequate judgment of life issues. The opposite is experienced.', 2020), 
('english', 'WAEC', 'I accidentally stepped on my brother but he told Mummy I did it _________.', 'thoughtfully', 'intuitively', 'deliberately', 'annoyingly', NULL, 'C', 'Accidentally describes an action done unintentionally. The opposite is deliberately, meaning done intentionally, on purpose.', 2020), 
('english', 'WAEC', 'The runner was _________ at fifteen seconds at the end of the race.', 'taped', 'timed', 'belled', 'flagged', NULL, 'B', 'Timed is the appropriate verb. It means to make sure how long it takes for something to happen or to measure the duration of how long it lasts.', 2020), 
('english', 'WAEC', 'The appellate court has _________ the decision of the lower court.', 'obstructed', 'nullified', 'neutralized', 'balanced', NULL, 'B', 'Nullify is the appropriate verb meaning to invalidate a legal decision or make a legal agreement that a decision or case have no legal force.', 2020), 
('english', 'WAEC', 'The defeated boxer left the ring looking extremely _________.', 'dislocated', 'distorted', 'deserted', 'dejected', NULL, 'D', 'Dejected is appropriate to describe the aftermath of defeat — looking unhappy, disappointed and despairful.', 2020), 
('english', 'WAEC', 'There is an election _________ pending against the senator.', 'application', 'appeal', 'petition', 'complaint', NULL, 'C', 'Petition means a request by a large number of people, to a court of law to take legal action against someone or political party, or for unfair electoral practices.', 2020), 
('english', 'WAEC', 'The manager was not in when Addo called, so he left his _________ card.', 'supplementary', 'complimentary', 'complementary', 'identification', NULL, 'C', 'A complementary card (business card) is a card given to clients making it easy for them to contact you. Complimentary is for commending or praising someone.', 2020), 
('english', 'WAEC', 'Coming from the kitchen was the sweet _________ of Mummy''s soup.', 'aroma', 'odour', 'fragrance', 'Scent', NULL, 'A', 'Aroma is the appropriate word for a strong pleasant smell, usually from cooked food or drink.', 2020), 
('english', 'WAEC', 'There is a need to raise teachers'' salary in order to boost their _________.', 'spirit', 'moral', 'soul', 'morale', NULL, 'D', 'Morale collocates with boost — the amount of confidence or encouragement felt by a person or group, especially when in a dangerous or difficult situation.', 2020), 
('english', 'WAEC', 'The librarian has not entered the new books in the _________.', 'catalogue', 'roster', 'list', 'directory', NULL, 'A', 'Catalogue is used in a library. It is a list of all the books that exist or are available in a library.', 2020), 
('english', 'WAEC', 'The textbook is very costly; I cannot _________ it to my students.', 'commit', 'afford', 'endorse', 'recommend', NULL, 'D', 'Recommend is the appropriate verb because it collocates with the preposition "to" in the sentence, as in "I cannot recommend it to my students".', 2020), 
('english', 'WAEC', 'The weather is too hot; I need some water to _________ my thirst.', 'wet', 'quench', 'cool', 'soak', NULL, 'B', 'Quench is the correct verb for the given sentence. It means to satisfy your thirst by having a drink.', 2020), 
('english', 'WAEC', 'My grandmother once told me that old habits die hard. This means that old habits are:', 'easily corrected', 'difficult to change', 'short-lived', 'forever changing', NULL, 'B', '"Old habits die hard" means it is difficult to learn new behaviour when you are used to behaving a certain way for a long time; difficult to break or stop a bad habit.', 2020), 
('english', 'WAEC', 'If you ask him to sing, he will do it at the drop of a hat. This means that he will sing:', 'joyfully', 'melodiously', 'immediately', 'sluggishly', NULL, 'C', '"At the drop of a hat" means doing something immediately and without any pressure.', 2020), 
('english', 'WAEC', 'The man has lost a lot and he only keeps up appearances by driving a big car. This means that the man:', 'intends to work harder', 'pretends that all is well', 'wants everybody to see him', 'wants to please his people', NULL, 'B', '"Keep up appearances" means to keep an outward show of prosperity or good behaviour when you are actually the opposite.', 2020), 
('english', 'WAEC', 'The game was tough but our team lost by a whisker. This means that our team lost by:', 'default', 'a wide margin', 'not preparing well', 'a narrow margin', NULL, 'D', '"By a whisker" means if something happens by a whisker, it happens by a very small amount or very slight opportunity.', 2020), 
('english', 'WAEC', 'When the result was announced, it was discovered that Bimbo and Pam were neck and neck. This means that Bimbo and Pam had:', 'the same result', 'failed badly', 'had equal results', 'passed well', NULL, 'C', '"Neck and neck" means if two competitors are level with each other and have an equal chance of winning.', 2020), 
('english', 'WAEC', 'The old woman''s birthday was marked by her children with pomp. This means that the birthday was:', 'greatly celebrated', 'remembered fondly', 'widely advertised', 'filmed and played back', NULL, 'A', '"With pomp" means a big, splendid and colorful ceremony that greatly attracts the public.', 2020), 
('english', 'WAEC', 'When the man was accused of stealing the money, nobody raised an eyebrow. This means that nobody was:', 'sad', 'pleased', 'interested', 'surprised', NULL, 'D', '"Raise eyebrows" means to cause surprise, shock or disapproval. Nobody raising an eyebrow means nobody was surprised.', 2020), 
('english', 'WAEC', 'People do not often rely on men who allow their exalted position to go to their head. This means that people shun those who are:', 'highly placed', 'conceited because of their position', 'rude because of their position', 'not doing their work', NULL, 'B', 'If something goes to someone''s head, it makes them think they are very important and makes them become conceited — letting fame/success go to their head.', 2020), 
('english', 'WAEC', 'The manager hit the roof when he was presented with the estimate for the new project. This means the manager:', 'mobilised the workers', 'became very angry', 'cancelled the project', 'became very suspicious', NULL, 'B', '"Hit the roof" means to get very angry or go into a rage.', 2020), 
('english', 'WAEC', 'When he received the news that he had lost the election, he did not bat an eyelid. This means that he:', 'expected to lose the election', 'stood perfectly still', 'was shocked to have lost', 'showed no feelings', NULL, 'D', '"Not bat an eyelid" means to show no sign or feeling of surprise or worry when something shocking or unexpected happens.', 2020), 
('english', 'WAEC', 'The boy was reluctant to carry out the order of his senior.', 'adamant', 'slow', 'sluggish', 'unwilling', NULL, 'D', 'Reluctant means not very willing to do something; therefore hesitant, disinclined, resisting, unenthusiastic.', 2020), 
('english', 'WAEC', 'Dr. Azeez declined the offer to chair the meeting.', 'rescinded', 'shunned', 'refused', 'avoided', NULL, 'C', 'In the given context, declined means to refuse, reject, turn down or not honour an offer, invitation, meeting, etc.', 2020), 
('english', 'WAEC', 'The match came to an abrupt end when the rain started.', 'sharp', 'brisk', 'quick', 'sudden', NULL, 'D', 'Abrupt describes something that is sudden and unexpected; unanticipated, unforeseen, startling, hurried.', 2020), 
('english', 'WAEC', 'The boy came through the window as stealthily as he could.', 'quietly', 'carefully', 'quickly', 'slowly', NULL, 'A', 'Stealthily describes an action done quietly and carefully in order not to be seen, heard or attract attention; secretly, furtively, covertly, sneakingly.', 2020), 
('english', 'WAEC', 'Bimbo was satisfied with the result she got.', 'positive', 'surprised', 'contented', 'appeased', NULL, 'C', 'Satisfied means being pleased because you have got what you wanted, or because you are happy with the outcome; contented, well pleased, happy.', 2020), 
('english', 'WAEC', 'It is absurd that people find it difficult to be honest.', 'strange', 'abnormal', 'alarming', 'interesting', NULL, 'B', 'Absurd describes something ridiculous or unreasonable; foolish in an amusing way; irrational, contrary to common sense, abnormal.', 2020), 
('english', 'WAEC', 'Even a mediocre student can pass that test.', 'dull', 'fresh', 'average', 'lazy', NULL, 'C', 'Mediocre means not very good; average; not extraordinary, exceptional or great.', 2020), 
('english', 'WAEC', 'We called the carpenter to repair the broken door.', 'restore', 'renovate', 'replace', 'mend', NULL, 'D', 'Repair means to put something that is damaged or broken back into good condition or make it work again; mend, fix, patch up.', 2020), 
('english', 'WAEC', 'Mrs. Okpala gave the drunk a contemptuous look.', 'nappy', 'sorrowful', 'knowing', 'scornful', NULL, 'D', 'Contemptuous describes a look that is scornful, embarrassing, debasing, disrespectful, derisive, sneering.', 2020), 
('english', 'WAEC', 'The Vice-Chancellor''s speech at the occasion was misconstrued.', 'misrepresented', 'misquoted', 'misunderstood', 'misreported', NULL, 'C', 'Misconstrue means to form a false understanding of the meaning or intention of something that someone says or does; to misinterpret, misunderstand, misconceive, misread.', 2020), 
('english', 'WAEC', 'The soldiers lay _________ the town to arrest the terrorists.', 'siege to', 'siege by', 'in siege to', 'in siege of', NULL, 'A', 'The correct collocation is "lay siege to". Siege as used this way goes with the preposition "to".', 2020), 
('english', 'WAEC', 'Power has not been restored to many parts of the town, so we set off _________.', 'to', 'in', 'for', 'with', NULL, 'A', 'The verb restore collocates or goes with only the preposition "to" anytime it is used.', 2020), 
('english', 'WAEC', 'We got to the hall after the play _________ started.', 'to', 'had', 'was', 'has', NULL, 'B', 'The sentence should read "we got to the hall after the play had started". Got is past tense while had started is past perfect tense.', 2020), 
('english', 'WAEC', 'The woman said the maid should go to _________ all the plates before going to bed.', 'wash', 'wash up', 'wash out', 'wash away', NULL, 'C', '"Wash (something) out" is a phrasal verb meaning to remove something like dirt or stain by washing.', 2020), 
('english', 'WAEC', 'John, would you mind lifting the box? _________, I wouldn''t.', 'Yes, I do', 'No, I wouldn''t', 'I wouldn''t', 'Yes, I would', NULL, 'B', 'In a question tag, the response must be consistent with the polarity that precedes it. The response should be "No, wouldn''t I" or "Yes, I would".', 2020), 
('english', 'WAEC', 'It was a long poem, but Rasheed learnt it _________.', 'in full', 'by rote', 'in detail', 'by heart', NULL, 'D', '"By heart" means to learn something so completely that you can say it from memory — commit to memory.', 2020), 
('english', 'WAEC', 'Let''s begin all over again, _________?', 'may we', 'shall we', 'can we', 'must we', NULL, 'B', '"Shall" and "will" can be used in the question tag with first person (I, we). "Let''s begin all over again" has "let us", so the question tag is shall we.', 2020), 
('english', 'WAEC', 'She is _________ driving carelessly.', 'rather driving carelessly', 'careless driving', 'carelessly drove', 'driving carelessly', NULL, 'A', 'The sentence should read "she is rather driving carelessly". Both rather and carelessly are adverbials qualifying driving. It is only grammatically correct that rather comes before the verb driving while carelessly follows the verb.', 2020), 
('english', 'WAEC', 'In the team, each player loves _________.', 'one another', 'themselves', 'each other', 'himself', NULL, 'A', 'The sentence needs a reciprocal pronoun "one another" to mean each person in the team likes the others. Note that "themselves" is reflexive.', 2020), 
('english', 'WAEC', 'This is the teacher _________ told me the answer.', 'who I said', 'which', 'who', 'whom', NULL, 'C', 'The sentence should read "This is the teacher who told me the answer." Who is a relative pronoun referring to the noun that is a subject of the second clause.', 2020), 
('english', 'WAEC', 'OUR Mathematics teacher has been transferred.', 'Has their Mathematics teacher been transferred?', 'Has our Physics teacher been transferred?', 'Has our Mathematics teacher been promoted?', 'Has our Mathematics supervisor been transferred?', NULL, 'D', 'The emphasis is on OUR. All other words remain intact. The response reinforces the emphasis: "No, it is rather OUR own Mathematics teacher that is transferred".', 2020);
