('english', 'NECO', 'This is the teacher _________ told me the answer.', 'who I said', 'which', 'who', 'whom', NULL, 'C', 'The sentence should read "This is the teacher who told me the answer." Who is a relative pronoun referring to the noun that is a subject of the second clause.', NULL), 
('english', 'NECO', 'OUR Mathematics teacher has been transferred.', 'Has their Mathematics teacher been transferred?', 'Has our Physics teacher been transferred?', 'Has our Mathematics teacher been promoted?', 'Has our Mathematics supervisor been transferred?', NULL, 'D', 'The emphasis is on OUR. All other words remain intact. The response reinforces the emphasis: "No, it is rather OUR own Mathematics teacher that is transferred".', NULL);
